import { Component, ViewChild } from '@angular/core';
import { ChildComponent } from './child.component';

@Component({
  selector: 'app-parent',
  template: `
    <p><button (click)="AddForChild()">Thêm vào</button></p>
    <app-child></app-child>
  `
})

export class ParentComponent {
  @ViewChild(ChildComponent) myChild: ChildComponent;
  AddForChild() {
    this.myChild.value1++;
    this.myChild.value2 += 111;
    this.myChild.OnClick();
  }
}
