import { Component, OnInit } from '@angular/core';
import { SignInService } from './sign-in.service';

@Component({
  selector: 'app-sign-in',
  template: `
    <form (ngSubmit)="onSubmit(formSignIn)" #formSignIn="ngForm">
      <h2>Sign In</h2>
      <input type="text" placeholder="Email" ngModel #email="ngModel" name="email" required>
      <p *ngIf="email.touched && email.errors !== null">Enter a valid email!</p>

      <input type="password" placeholder="Password" ngModel #pass="ngModel" name="password" minlength="4" required>
      <p *ngIf="pass.touched && pass.errors !== null">Enter a valid password!</p>

      <div ngModelGroup="KhoaHoc">
        <label><input type="checkbox" [ngModel]="false" name="mongodb"> MongoDB</label>
        <label><input type="checkbox" [ngModel]="true" name="expressjs"> ExpressJS</label>
        <label><input type="checkbox" [ngModel]="false" name="angular"> Angular</label>
        <label><input type="checkbox" [ngModel]="true" name="nodejs"> NodeJS</label>
      </div>

      <button [disabled]="formSignIn.invalid">Sign In</button>
    </form>

    <pre><code>{{pass.errors | json}}</code></pre>
  `,
  styleUrls: ['./sign-in.component.scss'],
  providers: [SignInService]
})

export class SignInComponent implements OnInit  {

  constructor(private signInService: SignInService) {}
  ngOnInit() {}

  onSubmit(formSignIn: any) {
    const value = formSignIn.value;
    this.signInService.postToExpress(value)
      .then(res => console.log(res))
      .catch(err => console.log(err));
  }
}
