import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-book',
  templateUrl: './book.component.html',
  styleUrls: ['./book.component.scss']
})
export class BookComponent implements OnInit {

  enValue2: string = '';
  viValue2: string = '';
  isShowForm: boolean = false;
  words: any[] = [
    { id: this.NewID(), en: 'actor', vi: 'hành động', memorized: true },
    { id: this.NewID(), en: 'activity', vi: 'hoạt động', memorized: false },
    { id: this.NewID(), en: 'active', vi: 'chủ động', memorized: true },
    { id: this.NewID(), en: 'bath', vi: 'tắm', memorized: true },
    { id: this.NewID(), en: 'bedroom', vi: 'phòng ngủ', memorized: false },
    { id: this.NewID(), en: 'keyboard', vi: 'bàn phím', memorized: true }
  ];
  filterStatus: string = 'TAT_CA';


  constructor() { }

  ngOnInit() {
  }

  ToggleForm() {
    this.isShowForm = !this.isShowForm;
  }
  ToggleMemorized(word: any) {
    word.memorized = !word.memorized;
  }

  NewID() {
    return (Math.ceil( Math.random() * 10000000 ));
  }
  SearchID(itemID: number) {
    for( let i = 0, len = this.words.length; i < len; i++ ) {
      const wordCur = this.words[i];
      if( wordCur.id == itemID ) {
        return i;
      }
    }
    return null;
  }
  ItemRemove(itemID: number) {
    const pos = this.SearchID(itemID);
    this.words.splice(pos, 1);
  }

  PushNewWord() {
    if( !this.isShowForm ) {
      this.isShowForm = true;
    }
    else {
      if( this.enValue2 !== '' && this.viValue2 !== '' ) {
        this.words.unshift({
          id: this.NewID(),
          en: this.enValue2,
          vi: this.viValue2,
          memorized: true
        });

        // Reset gia tri cua En && Vi
        this.enValue2 = '';
        this.viValue2 = '';
        // Hidden toggle Form
        this.isShowForm = false;
      }
      else {
        // Hidden toggle Form
        this.isShowForm = false;
      }
    }
  }

  FilterStatus() {
    console.log(this.filterStatus);
  }
  FilterContent(word: any) {
    switch(this.filterStatus) {
      case 'TAT_CA':
        return true;
      case 'TU_DA_NHO':
        return word.memorized;
      case 'TU_CHUA_NHO':
        return !word.memorized;
    }
  }

}
