import { Component, OnInit } from '@angular/core';
import { FormGroup, FormControl } from '@angular/forms';

@Component({
  selector: 'app-sign-up',
  template: `
    <form (ngSubmit)="OnSubmit()" [formGroup]="formSignUp">
      <h2>Sign Up</h2>
      <input type="text" placeholder="Email" formControlName="email">
      <!-- <p>Validation Email</p> -->

      <input type="password" placeholder="Password" formControlName="password">
      <!-- <p>Validation Password</p> -->

      <div formGroupName="meanapp">
        <label><input type="checkbox" formControlName="mongodb"> MongoDB</label>
        <label><input type="checkbox" formControlName="express"> Express</label>
        <label><input type="checkbox" formControlName="angular"> Angular</label>
        <label><input type="checkbox" formControlName="nodejs"> NodeJS</label>
      </div>

      <button>Sign Up</button>
    </form>
  `,
  styleUrls: ['./sign-in.component.scss']
})
export class SignUpComponent implements OnInit {
  formSignUp: FormGroup;

  constructor() {
    this.formSignUp = new FormGroup({
      email: new FormControl(),
      password: new FormControl(),
      meanapp: new FormGroup({
        mongodb: new FormControl(),
        express: new FormControl(),
        angular: new FormControl(),
        nodejs: new FormControl()
      })
    });
  }
  ngOnInit() { }

  OnSubmit() {
    console.log(this.formSignUp.value);
  }
}
