import { Injectable, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable()
export class WeatherService implements OnInit {
  private weatherAPI: string = 'http://api.openweathermap.org/data/2.5/weather?appid=9c83142eb677d93f91adcdc9e41823e2&units=metric';
  temperature: number = 0;

  constructor(private http: HttpClient) {}
  ngOnInit(): void {
  }
  getTemperature(city: string) {
    const api: string =`${this.weatherAPI}&q=${city}`;
    return this.http.get(api)
      .toPromise()
      .then(res => res)
      .then(resJson => resJson['main']['temp'])
      .catch(err => console.warn(err));
  }
}
